import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def calculate_travel_time(start, end, speed):
        distance = np.linalg.norm(end - start)
        return distance / speed

    def redundancy_cost(truck_position, other_truck_positions, target_position):
        redundancy_penalty = 0
        for pos in other_truck_positions:
            if np.linalg.norm(pos - target_position) < np.linalg.norm(truck_position - target_position):
                redundancy_penalty += 5  # Increasing this value strengthens avoidance of overlapping routes
        return redundancy_penalty

    def urgency_cost(arrival_time, window_start, window_end):
        if arrival_time < window_start:
            return (window_start - arrival_time)  # Waiting cost if early
        elif arrival_time > window_end:
            return (arrival_time - window_end) * 10  # High penalty if late
        else:
            return -1 / (window_end - arrival_time + 1)  # Prefer imminent closing windows

    best_node = None
    best_cost = float('inf')

    other_truck_positions = [pos for pos in all_truck_pos if not np.array_equal(pos, cur_truck_pos)]

    for idx, customer in enumerate(unvisited_customers):
        window_start, window_end = time_windows[idx]
        travel_time = calculate_travel_time(cur_truck_pos, customer, truck_speed)
        arrival_time = current_time + travel_time
        red_cost = redundancy_cost(cur_truck_pos, other_truck_positions, customer)
        ur_cost = urgency_cost(arrival_time, window_start, window_end)
        cost = travel_time + ur_cost + red_cost

        if cost < best_cost:
            best_cost = cost
            best_node = idx

    return best_node
